import re

def solve(code: list[str], businessLine: list[str], isActive: list[bool]) -> list[str]:
    allowed_business = {"electronics", "grocery", "pharmacy", "restaurant"}
    business_order = {"electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3}
    valid = []
    for i in range(len(code)):
        c = code[i]
        b = businessLine[i]
        a = isActive[i]
        if not c:
            continue
        if b not in allowed_business:
            continue
        if not a:
            continue
        if not re.fullmatch(r'^\w+$', c):
            continue
        valid.append((b, c))
    valid.sort(key=lambda x: (business_order[x[0]], x[1]))
    return [c for (b, c) in valid]
